solution.javascript:
import { test, expect } from '@playwright/test';

test('work with iframes', async ({ page }) => {
  await page.goto('https://practice.expandtesting.com/iframe');

  const frame = page.frameLocator('#mce_0_ifr');
  const editor = frame.locator('#tinymce');

  await editor.clear();
  await editor.fill('Hello from Playwright!');

  await expect(editor).toContainText('Hello from Playwright!');

  // Alternative: using page.frame()
  const frameElement = page.frame({ url: /.*iframe.*/ });
  if (frameElement) {
    const content = await frameElement.locator('#tinymce').textContent();
    expect(content).toContain('Hello');
  }
});

